"""
================================================================================
MOTOR DE CÁLCULO DE INDICADORES FINANCIEROS
================================================================================
Este módulo contiene las funciones para:
  1. Cargar y normalizar la hoja de BALANCES
  2. Calcular el indicador de SOLVENCIA replicando exactamente la lógica
     de la hoja "CALCULO SOLVENCIA" del Excel
  3. Devolver una estructura de resultados lista para ser graficada en HTML

Diseño extensible: para añadir nuevos indicadores (liquidez, rentabilidad,
endeudamiento, etc.) basta con crear nuevas funciones siguiendo el patrón
de `calcular_solvencia()`.
================================================================================
"""

import pandas as pd
# (config ya está definido arriba en este mismo archivo)


# ==============================================================================
# CARGA Y NORMALIZACIÓN DE LA HOJA BALANCES
# ==============================================================================

def cargar_balances(ruta_excel: str, hoja: str = "BALANCES") -> pd.DataFrame:
    """
    Carga la hoja de BALANCES desde el archivo Excel y la normaliza.
    
    - Estandariza nombres de columnas (resuelve caracteres con problemas de encoding)
    - Convierte CUENTA a string para evitar problemas con códigos numéricos
    - Normaliza el MES a MAYÚSCULAS (en el archivo hay mezcla: 'Enero' vs 'ENERO')
    - Calcula columna SALDO_ABS = |NUEVO SALDO| (equivalente a columna J del Excel)
    """
    df = pd.read_excel(ruta_excel, sheet_name=hoja, dtype={"CUENTA": str})
    
    # Renombrar columnas con problemas de encoding (DÉBITO/CRÉDITO)
    rename_map = {}
    for col in df.columns:
        if "BITO" in col.upper():
            rename_map[col] = "DEBITO"
        elif "DITO" in col.upper():
            rename_map[col] = "CREDITO"
    df = df.rename(columns=rename_map)
    
    # Normalizar MES y CUENTA
    df["MES"] = df["MES"].astype(str).str.upper().str.strip()
    df["CUENTA"] = df["CUENTA"].astype(str).str.strip()
    
    # SALDO_ABS replica la columna J (=ABS(I)) del Excel
    df["SALDO_ABS"] = df["NUEVO SALDO"].abs()
    
    # NUEVO SALDO se conserva con signo (columna I del Excel)
    df["SALDO_SIGNADO"] = df["NUEVO SALDO"]
    
    return df


