        '145510','145515','145520','145525',
        # Comercial
        '146110','146115','146120','146125','146210','146215','146220','146225',
        # Empleados (vivienda y consumo)
        '146905','146910','146915','146920','146925',
        '146930','146935','146940','146945','146950',
        # DETERIOROS por modalidad
        '140805','140810','140815','140820','140825',  # Vivienda
        '144505','144510','144515','144520','144525','144530','144535','144540','144545','144550',  # Consumo
        '145805','145810','145815','145820','145825','145830','145835','145840','145845','145850',  # Comercial/Microcrédito
        '147105','147110','147115','147120','147125',  # Empleados vivienda
        '147130','147135','147140','147145','147150',  # Empleados consumo
        # MORA (cuentas memorando 84xxxx)
