def listar_periodos(df: pd.DataFrame) -> list[tuple[int, str]]:
    """Devuelve la lista de períodos disponibles (año, mes) ordenados cronológicamente."""
    orden_meses = {m: i for i, m in enumerate([
        "ENERO", "FEBRERO", "MARZO", "ABRIL", "MAYO", "JUNIO",
        "JULIO", "AGOSTO", "SEPTIEMBRE", "OCTUBRE", "NOVIEMBRE", "DICIEMBRE"
    ])}
    periodos = df[["AÑO", "MES"]].drop_duplicates()
    periodos["orden"] = periodos["MES"].map(orden_meses)
    periodos = periodos.sort_values(["AÑO", "orden"])
    return [(int(r["AÑO"]), r["MES"]) for _, r in periodos.iterrows()]


# ==============================================================================
# FUNCIÓN BASE: SUMIFS al estilo Excel
# ==============================================================================

def sumar_cuenta(df: pd.DataFrame, cuenta: str, anio: int, mes: str,
                 columna: str = "SALDO_ABS") -> float:
    """
    Replica =SUMIFS(BALANCES!$J:$J, BALANCES!$D:$D, cuenta, B:B, año, C:C, mes)/1000000
    
    Devuelve el saldo de la cuenta en el período indicado, expresado en millones.
    
    Parámetros:
      - columna: 'SALDO_ABS' (col J, valor absoluto) o 'SALDO_SIGNADO' (col I, con signo)
    """
    mask = (
        (df["CUENTA"] == str(cuenta)) &
        (df["AÑO"] == anio) &
        (df["MES"] == mes.upper())
    )
    return df.loc[mask, columna].sum() / 1_000_000


# ==============================================================================
# CÁLCULO DEL INDICADOR DE SOLVENCIA
# ==============================================================================

def _calcular_componente(df, componente, anio, mes):
    """Calcula un componente individual del modelo (valor absoluto y ponderado)."""
    # Caso especial: deterioro de Saludcoop. En el Excel, esta línea es D24 = -D18*1,
    # es decir, NO suma la cuenta 122699 completa, sino que usa el valor de Saludcoop
    # (122602001) con signo negativo, para neutralizar a Saludcoop en el patrimonio.
    if componente.get("tipo") == "deterioro_saludcoop":
        valor_saludcoop = sumar_cuenta(df, "122602001", anio, mes, "SALDO_ABS")
        valor_signado = valor_saludcoop * componente.get("signo", -1)
        ponderado = valor_signado * componente.get("ponderacion", 1.0)
        return {
            "cuenta": componente["cuenta"],
            "nombre": componente["nombre"],
            "ponderacion": componente.get("ponderacion", 1.0),
            "valor": valor_signado,
            "ponderado": ponderado,
        }
    
    # Caso especial: deterioro de Aportes Alianza Fiduciaria.
    # En el Excel, D25 = D18 - SUMIFS(122699) = Saludcoop - Total122699 = -(Alianza)
    # Por tanto, el valor es -(122699 total - Saludcoop)
    if componente.get("tipo") == "deterioro_alianza":
        total_122699 = sumar_cuenta(df, "122699", anio, mes, "SALDO_ABS")
        valor_saludcoop = sumar_cuenta(df, "122602001", anio, mes, "SALDO_ABS")
        # En Excel: D25 = D18 - SUMIFS(122699) → si SUMIFS=158.77, D18=127.77 → D25 = -30.99
        valor_excel = valor_saludcoop - total_122699
        ponderado = valor_excel * componente.get("ponderacion", 0.0)
        return {
            "cuenta": componente["cuenta"],
            "nombre": componente["nombre"],
            "ponderacion": componente.get("ponderacion", 0.0),
            "valor": valor_excel,
            "ponderado": ponderado,
        }
    
    columna = "SALDO_SIGNADO" if componente.get("columna") == "I" else "SALDO_ABS"
    valor = sumar_cuenta(df, componente["cuenta"], anio, mes, columna)
    valor_signado = valor * componente.get("signo", 1)
    ponderado = valor_signado * componente.get("ponderacion", 0)
    return {
        "cuenta": componente["cuenta"],
        "nombre": componente["nombre"],
        "ponderacion": componente.get("ponderacion", 0),
        "valor": valor_signado,
        "ponderado": ponderado,
    }


def calcular_solvencia(df: pd.DataFrame, anio: int, mes: str) -> dict:
    """
    Calcula el indicador de solvencia para el período (anio, mes).
    
    Retorna un diccionario con:
      - grupos_activos: detalle por grupo (efectivo, cartera, etc.)
      - total_activos_ponderados
      - cuentas_contingentes
      - patrimonio_basico
      - deducciones
      - patrimonio_adicional
      - patrimonio_tecnico
      - solvencia (índice)
      - cumple_solvencia (bool)
      - limites_operativos
    """
    mes = mes.upper()
    
    # --------------------------------------------------------------------------
    # 1. ACTIVOS PONDERADOS POR RIESGO
    # --------------------------------------------------------------------------
    detalle_grupos = {}
    total_activos_ponderados = 0.0
    total_activos_absolutos = 0.0
    
    for nombre_grupo, componentes in GRUPOS_ACTIVOS.items():
        items = [_calcular_componente(df, c, anio, mes) for c in componentes]
        subtotal_valor = sum(it["valor"] for it in items)
        subtotal_ponderado = sum(it["ponderado"] for it in items)
        detalle_grupos[nombre_grupo] = {
            "items": items,
            "subtotal_valor": subtotal_valor,
            "subtotal_ponderado": subtotal_ponderado,
        }
        total_activos_absolutos += subtotal_valor
        total_activos_ponderados += subtotal_ponderado
    
    # --------------------------------------------------------------------------
    # 2. CUENTAS CONTINGENTES (riesgo fuera de balance)
    # --------------------------------------------------------------------------
    items_contingentes = [_calcular_componente(df, c, anio, mes) for c in CUENTAS_CONTINGENTES]
    subtotal_contingentes = sum(it["ponderado"] for it in items_contingentes)
    
    # Total activos ponderados por riesgo (APR) = balance + contingentes
    apr_total = total_activos_ponderados + subtotal_contingentes
    
    # --------------------------------------------------------------------------
    # 3. PATRIMONIO BÁSICO
    # --------------------------------------------------------------------------
    items_pb = [_calcular_componente(df, c, anio, mes) for c in PATRIMONIO_BASICO]
    patrimonio_basico = sum(it["ponderado"] for it in items_pb)
    
    # --------------------------------------------------------------------------
    # 4. DEDUCCIONES DEL PATRIMONIO BÁSICO
    # --------------------------------------------------------------------------
    items_deducciones = []
    for d in DEDUCCIONES_PATRIMONIO:
        tipo = d.get("tipo", "")
        # Excedentes: solo se restan si son negativos
        if tipo in ("excedentes_acum_negativos", "excedentes_ejer_negativos"):
            valor_signado = sumar_cuenta(df, d["cuenta"], anio, mes, "SALDO_SIGNADO")
            # En el Excel: =IF(D<0, D*C, 0). Como deducción suma a deducciones
            ponderado = valor_signado * d["ponderacion"] if valor_signado < 0 else 0
            items_deducciones.append({
                "cuenta": d["cuenta"], "nombre": d["nombre"],
                "ponderacion": d["ponderacion"], "valor": valor_signado, "ponderado": ponderado
            })
        else:
            items_deducciones.append(_calcular_componente(df, d, anio, mes))
    
    total_deducciones = sum(it["ponderado"] for it in items_deducciones)
    
    # --------------------------------------------------------------------------
    # 5. PATRIMONIO ADICIONAL
    # --------------------------------------------------------------------------
    items_pa = []
    for c in PATRIMONIO_ADICIONAL:
        tipo = c.get("tipo", "")
        if tipo in ("excedentes_acum_positivos", "excedentes_ejer_positivos"):
            valor = sumar_cuenta(df, c["cuenta"], anio, mes, "SALDO_SIGNADO")
            ponderado = valor * c["ponderacion"] if valor > 0 else 0
            items_pa.append({
                "cuenta": c["cuenta"], "nombre": c["nombre"],
                "ponderacion": c["ponderacion"], "valor": valor, "ponderado": ponderado
            })
        elif tipo == "provision_general":
            # Provisión general (cuenta 1468) aporta al Patrimonio Adicional pero
            # tiene un TOPE del 1.25% del APR.
            #   - Si provisión < tope: cuenta completa
            #   - Si provisión >= tope: se topa al 1.25% del APR
            valor_provision = sumar_cuenta(df, c["cuenta"], anio, mes, "SALDO_ABS")
            tope_125 = TOPE_PROVISIONES_GENERALES * apr_total
            ponderado = min(valor_provision, tope_125)
            items_pa.append({
                "cuenta": c["cuenta"], "nombre": c["nombre"],
                "ponderacion": 1.0, "valor": valor_provision, "ponderado": ponderado
            })
    
    total_patrimonio_adicional = sum(it["ponderado"] for it in items_pa)
    
    # --------------------------------------------------------------------------
    # 6. PATRIMONIO TÉCNICO E ÍNDICE DE SOLVENCIA
    # --------------------------------------------------------------------------
    patrimonio_tecnico = patrimonio_basico - total_deducciones + total_patrimonio_adicional
    solvencia = patrimonio_tecnico / apr_total if apr_total > 0 else 0
    
    # --------------------------------------------------------------------------
    # 7. LÍMITES OPERATIVOS
    # --------------------------------------------------------------------------
    limites = {
        "tope_ahorradores":      patrimonio_tecnico * LIMITE_AHORRADORES,
        "tope_deudores":         patrimonio_tecnico * LIMITE_DEUDORES,
        "tope_cupo_individual":  patrimonio_tecnico * LIMITE_CUPO_INDIVIDUAL,
        "tope_cupo_febor":       patrimonio_tecnico * LIMITE_CUPO_INDIVIDUAL_FEBOR,
        "tope_inversiones":      patrimonio_tecnico * LIMITE_INVERSIONES,
    }
    
    # --------------------------------------------------------------------------
    # 8. FONDO DE LIQUIDEZ vs DEPÓSITOS
    # --------------------------------------------------------------------------
    fondo_liquidez = (
        sumar_cuenta(df, "1203", anio, mes) +
        sumar_cuenta(df, "1120", anio, mes)
    )
    depositos = (
        sumar_cuenta(df, "21", anio, mes) -
        sumar_cuenta(df, "210595", anio, mes) -
        sumar_cuenta(df, "211095", anio, mes) -
        sumar_cuenta(df, "212595", anio, mes) -
        sumar_cuenta(df, "213095", anio, mes)
    )
    ratio_liquidez = fondo_liquidez / depositos if depositos > 0 else 0
    
    return {
        "periodo": f"{mes} {anio}",
        "anio": anio,
        "mes": mes,
        # Activos
        "grupos_activos": detalle_grupos,
        "total_activos_absolutos": total_activos_absolutos,
        "total_activos_ponderados_balance": total_activos_ponderados,
        "items_contingentes": items_contingentes,
        "subtotal_contingentes": subtotal_contingentes,
        "apr_total": apr_total,
        # Patrimonio
        "items_patrimonio_basico": items_pb,
        "patrimonio_basico": patrimonio_basico,
        "items_deducciones": items_deducciones,
        "total_deducciones": total_deducciones,
        "items_patrimonio_adicional": items_pa,
        "patrimonio_adicional": total_patrimonio_adicional,
        "patrimonio_tecnico": patrimonio_tecnico,
        # Indicador
        "solvencia": solvencia,
        "solvencia_requerida": REQUERIMIENTO_SOLVENCIA,
        "cumple_solvencia": solvencia >= REQUERIMIENTO_SOLVENCIA,
        "holgura_solvencia": solvencia - REQUERIMIENTO_SOLVENCIA,
        # Liquidez
        "fondo_liquidez": fondo_liquidez,
        "depositos_netos": depositos,
        "ratio_liquidez": ratio_liquidez,
        "ratio_liquidez_requerido": LIMITE_FONDO_LIQUIDEZ if False else 0.10,
        # Límites operativos
        "limites_operativos": limites,
    }


# ==============================================================================
# CÁLCULO DE INDICADORES PARA SERIES DE PERÍODOS
# ==============================================================================

def calcular_serie_solvencia(df: pd.DataFrame, periodos: list[tuple[int, str]]) -> list[dict]:
    """
    Calcula la solvencia para una lista de períodos y devuelve la serie
    histórica para gráficos de tendencia.
    """
    return [calcular_solvencia(df, anio, mes) for anio, mes in periodos]



